# start-claude-dev.ps1
# Quick launcher for Claude Code CLI development sessions
# Usage: Right-click → Run with PowerShell, or create a shortcut

#Requires -Version 7.0

param(
    [string]$ProjectPath = "D:\Proton Drive\My files\Documents\Professional\Programming\Web Development\system.knowledgebase",
    [switch]$SkipUpdates,
    [switch]$StartClaude,
    [switch]$ForceUpdates  # Force update even with install technology mismatch
)

$ErrorActionPreference = "Continue"

Write-Host "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host "  Claude Code Development Environment Setup" -ForegroundColor Cyan
Write-Host "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host ""

# 1. Check and Update PowerShell
Write-Host "[1/4] Checking PowerShell..." -ForegroundColor Yellow
$currentVersion = $PSVersionTable.PSVersion
Write-Host "      Current: PowerShell $($currentVersion.Major).$($currentVersion.Minor).$($currentVersion.Patch)" -ForegroundColor Gray

if (-not $SkipUpdates) {
    try {
        # Check if update is available
        $updateCheck = winget list --id Microsoft.PowerShell --accept-source-agreements 2>&1 | Out-String

        if ($updateCheck -match "Available|upgrade available" -or $updateCheck -match "(\d+\.\d+\.\d+)\s+(\d+\.\d+\.\d+)") {
            Write-Host "      Update available - attempting upgrade..." -ForegroundColor Magenta

            # Try standard upgrade first
            $upgradeResult = winget upgrade Microsoft.PowerShell --accept-package-agreements --accept-source-agreements 2>&1 | Out-String

            if ($upgradeResult -match "install technology is different") {
                Write-Host "      Install method mismatch detected - fixing..." -ForegroundColor Yellow

                # Need to uninstall and reinstall via winget
                # This requires elevation and will be done in a separate process
                $script = @'
Write-Host "Reinstalling PowerShell via winget..." -ForegroundColor Cyan
Write-Host "Step 1: Uninstalling current version..." -ForegroundColor Yellow
winget uninstall Microsoft.PowerShell --accept-source-agreements --silent
Start-Sleep -Seconds 2
Write-Host "Step 2: Installing latest version..." -ForegroundColor Yellow
winget install Microsoft.PowerShell --accept-package-agreements --accept-source-agreements --silent
Write-Host ""
Write-Host "PowerShell updated! Close this window and reopen your terminal." -ForegroundColor Green
Write-Host "Press any key to exit..."
$null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
'@

                # Save script to temp file
                $tempScript = [System.IO.Path]::GetTempFileName() + ".ps1"
                $script | Out-File -FilePath $tempScript -Encoding UTF8

                Write-Host "      Launching elevated installer (requires admin)..." -ForegroundColor Yellow
                Write-Host "      After update completes, close this window and reopen." -ForegroundColor Yellow

                # Launch elevated PowerShell to do the reinstall
                Start-Process pwsh -ArgumentList "-NoProfile", "-ExecutionPolicy", "Bypass", "-File", $tempScript -Verb RunAs -Wait

                # Clean up temp file
                Remove-Item $tempScript -ErrorAction SilentlyContinue

                Write-Host "      PowerShell update initiated" -ForegroundColor Green
            }
            elseif ($upgradeResult -match "Successfully installed|No applicable upgrade") {
                Write-Host "      PowerShell updated successfully!" -ForegroundColor Green
            }
            else {
                # Might already be up to date or minor issue
                Write-Host "      PowerShell is up to date" -ForegroundColor Green
            }
        }
        else {
            Write-Host "      PowerShell is up to date" -ForegroundColor Green
        }
    }
    catch {
        Write-Host "      Could not check for updates: $_" -ForegroundColor Gray
    }
}

# 2. Check Node.js
Write-Host ""
Write-Host "[2/4] Checking Node.js..." -ForegroundColor Yellow
try {
    $nodeVersion = node --version 2>&1
    if ($LASTEXITCODE -eq 0) {
        Write-Host "      Node.js $nodeVersion installed" -ForegroundColor Green
    } else {
        throw "Node not found"
    }
} catch {
    Write-Host "      ERROR: Node.js not found! Install from https://nodejs.org" -ForegroundColor Red
    Write-Host "      Or run: winget install OpenJS.NodeJS.LTS" -ForegroundColor Yellow
}

# 3. Update Claude Code CLI
Write-Host ""
Write-Host "[3/4] Checking Claude Code CLI..." -ForegroundColor Yellow
try {
    $claudeVersion = claude --version 2>&1
    if ($LASTEXITCODE -eq 0) {
        Write-Host "      Current: $claudeVersion" -ForegroundColor Gray

        if (-not $SkipUpdates) {
            Write-Host "      Checking for updates..." -ForegroundColor Gray
            $updateResult = claude update 2>&1 | Out-String

            if ($updateResult -match "already.*latest|up to date|no update available") {
                Write-Host "      Claude Code CLI is up to date" -ForegroundColor Green
            }
            elseif ($updateResult -match "updated|Updating|Installing|downloaded") {
                Write-Host "      Updated successfully!" -ForegroundColor Green
                $newVersion = claude --version 2>&1
                Write-Host "      New version: $newVersion" -ForegroundColor Green
            }
            else {
                Write-Host "      Claude Code CLI is up to date" -ForegroundColor Green
            }
        }
    } else {
        throw "Claude not found"
    }
} catch {
    Write-Host "      ERROR: Claude Code CLI not found!" -ForegroundColor Red
    Write-Host "      Install: npm install -g @anthropic-ai/claude-code" -ForegroundColor Yellow
}

# 4. Navigate to project
Write-Host ""
Write-Host "[4/4] Navigating to project..." -ForegroundColor Yellow
if (Test-Path $ProjectPath) {
    Set-Location $ProjectPath
    Write-Host "      $ProjectPath" -ForegroundColor Green
} else {
    Write-Host "      WARNING: Project path not found: $ProjectPath" -ForegroundColor Yellow
    Write-Host "      Staying in current directory" -ForegroundColor Gray
}

# Summary
Write-Host ""
Write-Host "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host "  Ready! Type 'claude' to start Claude Code CLI" -ForegroundColor Green
Write-Host "═══════════════════════════════════════════════════════════" -ForegroundColor Cyan
Write-Host ""

# Optionally start Claude immediately
if ($StartClaude) {
    Write-Host "Starting Claude Code CLI..." -ForegroundColor Cyan
    claude
}

